import { create } from 'zustand'
import { clearProjectCaches } from '../utils/lruCache'

export interface ProjectCategory {
  id: string
  name: string
  collapsed: boolean
  order: number
}

export interface Project {
  path: string
  name: string
  executable?: string
  apiPort?: number
  apiAutoStart?: boolean
  apiSessionMode?: 'existing' | 'new-keep' | 'new-close'
  apiModel?: 'default' | 'opus' | 'sonnet' | 'haiku'
  autoAcceptTools?: string[]
  permissionMode?: string
  color?: string
  ttsVoice?: string
  ttsEngine?: 'piper' | 'xtts'
  backend?: 'default' | 'claude' | 'gemini' | 'codex' | 'opencode' | 'aider'
  categoryId?: string
  order?: number
}

export interface OpenTab {
  id: string
  projectPath: string
  sessionId?: string
  title: string
  ptyId: string
  backend?: 'default' | 'claude' | 'gemini' | 'codex' | 'opencode' | 'aider'
}

interface WorkspaceState {
  projects: Project[]
  openTabs: OpenTab[]
  activeTabId: string | null
  categories: ProjectCategory[]

  setProjects: (projects: Project[]) => void
  addProject: (project: Project) => void
  removeProject: (path: string) => void
  updateProject: (path: string, updates: Partial<Project>) => void

  addTab: (tab: OpenTab) => void
  removeTab: (id: string) => void
  updateTab: (id: string, updates: Partial<OpenTab>) => void
  setActiveTab: (id: string) => void
  clearTabs: () => void

  setCategories: (categories: ProjectCategory[]) => void
  addCategory: (name: string) => string
  updateCategory: (id: string, updates: Partial<ProjectCategory>) => void
  removeCategory: (id: string) => void
  reorderCategories: (ids: string[]) => void
  moveProjectToCategory: (projectPath: string, categoryId: string | null) => void
  reorderProjects: (categoryId: string | null, projectPaths: string[]) => void
}

const generateCategoryId = (): string =>
  `cat-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`

export const useWorkspaceStore = create<WorkspaceState>((set, get) => ({
  projects: [],
  openTabs: [],
  activeTabId: null,
  categories: [],

  setProjects: (projects) => set({ projects }),

  addProject: (project) => {
    const { projects } = get()
    if (!projects.find((p) => p.path === project.path)) {
      set({ projects: [...projects, project] })
    }
  },

  removeProject: (path) => {
    const { projects } = get()
    clearProjectCaches(path)
    set({ projects: projects.filter((p) => p.path !== path) })
  },

  updateProject: (path, updates) => {
    const { projects } = get()
    set({
      projects: projects.map((p) =>
        p.path === path ? { ...p, ...updates } : p
      )
    })
  },

  addTab: (tab) => {
    const { openTabs } = get()
    set({
      openTabs: [...openTabs, tab],
      activeTabId: tab.id
    })
  },

  removeTab: (id) => {
    const { openTabs, activeTabId } = get()
    const newTabs = openTabs.filter((t) => t.id !== id)
    let newActiveId = activeTabId

    if (activeTabId === id) {
      const index = openTabs.findIndex((t) => t.id === id)
      if (newTabs.length > 0) {
        newActiveId = newTabs[Math.min(index, newTabs.length - 1)].id
      } else {
        newActiveId = null
      }
    }

    set({ openTabs: newTabs, activeTabId: newActiveId })
  },

  updateTab: (id, updates) => {
    const { openTabs } = get()
    set({
      openTabs: openTabs.map((t) =>
        t.id === id ? { ...t, ...updates } : t
      )
    })
  },

  setActiveTab: (id) => set({ activeTabId: id }),

  clearTabs: () => set({ openTabs: [], activeTabId: null }),

  setCategories: (categories) => set({ categories }),

  addCategory: (name) => {
    const { categories } = get()
    const id = generateCategoryId()
    const maxOrder = categories.reduce((max, c) => Math.max(max, c.order), -1)
    set({
      categories: [...categories, { id, name, collapsed: false, order: maxOrder + 1 }]
    })
    return id
  },

  updateCategory: (id, updates) => {
    const { categories } = get()
    set({
      categories: categories.map((c) =>
        c.id === id ? { ...c, ...updates } : c
      )
    })
  },

  removeCategory: (id) => {
    const { categories, projects } = get()
    set({
      categories: categories.filter((c) => c.id !== id),
      projects: projects.map((p) =>
        p.categoryId === id ? { ...p, categoryId: undefined } : p
      )
    })
  },

  reorderCategories: (ids) => {
    const { categories } = get()
    set({
      categories: categories.map((c) => ({
        ...c,
        order: ids.indexOf(c.id)
      }))
    })
  },

  moveProjectToCategory: (projectPath, categoryId) => {
    const { projects } = get()
    const categoryProjects = projects.filter((p) =>
      categoryId === null ? !p.categoryId : p.categoryId === categoryId
    )
    const maxOrder = categoryProjects.reduce((max, p) => Math.max(max, p.order ?? -1), -1)
    set({
      projects: projects.map((p) =>
        p.path === projectPath
          ? { ...p, categoryId: categoryId ?? undefined, order: maxOrder + 1 }
          : p
      )
    })
  },

  reorderProjects: (categoryId, projectPaths) => {
    const { projects } = get()
    set({
      projects: projects.map((p) => {
        const index = projectPaths.indexOf(p.path)
        if (index >= 0) {
          return { ...p, order: index }
        }
        return p
      })
    })
  }
}))

import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest'
import { join } from 'path'

// Mock electron app module before importing session-store
vi.mock('electron', () => ({
  app: {
    getPath: vi.fn().mockReturnValue('/mock/userData')
  }
}))

// Mock fs module
vi.mock('fs', () => ({
  existsSync: vi.fn(),
  mkdirSync: vi.fn(),
  readFileSync: vi.fn(),
  writeFileSync: vi.fn()
}))

import { SessionStore, Workspace, Settings, WindowBounds } from '../session-store'
import * as fs from 'fs'

describe('SessionStore', () => {
  const mockConfigDir = '/mock/userData/config'
  const mockConfigPath = join(mockConfigDir, 'workspace.json')

  beforeEach(() => {
    vi.clearAllMocks()
  })

  afterEach(() => {
    vi.restoreAllMocks()
  })

  describe('constructor', () => {
    it('should create config directory if it does not exist', () => {
      vi.mocked(fs.existsSync).mockReturnValueOnce(false) // config dir check
      vi.mocked(fs.existsSync).mockReturnValueOnce(false) // workspace.json check

      new SessionStore()

      expect(fs.mkdirSync).toHaveBeenCalledWith(mockConfigDir, { recursive: true })
    })

    it('should not create config directory if it already exists', () => {
      vi.mocked(fs.existsSync).mockReturnValueOnce(true) // config dir exists
      vi.mocked(fs.existsSync).mockReturnValueOnce(false) // workspace.json doesn't exist

      new SessionStore()

      expect(fs.mkdirSync).not.toHaveBeenCalled()
    })
  })

  describe('load()', () => {
    it('should return default workspace when workspace.json does not exist', () => {
      vi.mocked(fs.existsSync).mockReturnValueOnce(true) // config dir exists
      vi.mocked(fs.existsSync).mockReturnValueOnce(false) // workspace.json doesn't exist

      const store = new SessionStore()
      const workspace = store.getWorkspace()

      expect(workspace).toEqual({
        projects: [],
        openTabs: [],
        activeTabId: null
      })
    })

    it('should load workspace from existing workspace.json', () => {
      const mockWorkspace: Workspace = {
        projects: [{ path: '/test', name: 'Test Project' }],
        openTabs: [{ id: 'tab1', projectPath: '/test', title: 'Test Tab' }],
        activeTabId: 'tab1'
      }
      const mockData = { workspace: mockWorkspace }

      vi.mocked(fs.existsSync).mockReturnValueOnce(true) // config dir
      vi.mocked(fs.existsSync).mockReturnValueOnce(true) // workspace.json exists
      vi.mocked(fs.readFileSync).mockReturnValueOnce(JSON.stringify(mockData))

      const store = new SessionStore()
      const workspace = store.getWorkspace()

      expect(workspace).toEqual(mockWorkspace)
      expect(fs.readFileSync).toHaveBeenCalledWith(mockConfigPath, 'utf-8')
    })

    it('should return default workspace when workspace.json is corrupted', () => {
      vi.mocked(fs.existsSync).mockReturnValueOnce(true) // config dir
      vi.mocked(fs.existsSync).mockReturnValueOnce(true) // workspace.json exists
      vi.mocked(fs.readFileSync).mockReturnValueOnce('invalid json {{{')

      // Spy on console.error to verify error logging
      const consoleSpy = vi.spyOn(console, 'error').mockImplementation(() => {})

      const store = new SessionStore()
      const workspace = store.getWorkspace()

      expect(workspace).toEqual({
        projects: [],
        openTabs: [],
        activeTabId: null
      })
      expect(consoleSpy).toHaveBeenCalled()
      consoleSpy.mockRestore()
    })

    it('should return default workspace when readFileSync throws', () => {
      vi.mocked(fs.existsSync).mockReturnValueOnce(true) // config dir
      vi.mocked(fs.existsSync).mockReturnValueOnce(true) // workspace.json exists
      vi.mocked(fs.readFileSync).mockImplementationOnce(() => {
        throw new Error('EACCES: permission denied')
      })

      const consoleSpy = vi.spyOn(console, 'error').mockImplementation(() => {})

      const store = new SessionStore()
      const workspace = store.getWorkspace()

      expect(workspace).toEqual({
        projects: [],
        openTabs: [],
        activeTabId: null
      })
      expect(consoleSpy).toHaveBeenCalled()
      consoleSpy.mockRestore()
    })

    it('should handle empty workspace.json file', () => {
      vi.mocked(fs.existsSync).mockReturnValueOnce(true) // config dir
      vi.mocked(fs.existsSync).mockReturnValueOnce(true) // workspace.json exists
      vi.mocked(fs.readFileSync).mockReturnValueOnce('')

      const consoleSpy = vi.spyOn(console, 'error').mockImplementation(() => {})

      const store = new SessionStore()
      const workspace = store.getWorkspace()

      // Empty string causes JSON.parse to throw
      expect(workspace).toEqual({
        projects: [],
        openTabs: [],
        activeTabId: null
      })
      consoleSpy.mockRestore()
    })
  })

  describe('save()', () => {
    it('should save workspace to workspace.json', () => {
      vi.mocked(fs.existsSync).mockReturnValue(true)
      vi.mocked(fs.readFileSync).mockReturnValueOnce(JSON.stringify({
        workspace: { projects: [], openTabs: [], activeTabId: null }
      }))

      const store = new SessionStore()
      const newWorkspace: Workspace = {
        projects: [{ path: '/new', name: 'New Project' }],
        openTabs: [],
        activeTabId: null
      }

      store.saveWorkspace(newWorkspace)

      expect(fs.writeFileSync).toHaveBeenCalledWith(
        mockConfigPath,
        expect.stringContaining('"projects"')
      )
    })

    it('should handle write errors gracefully', () => {
      vi.mocked(fs.existsSync).mockReturnValue(true)
      vi.mocked(fs.readFileSync).mockReturnValueOnce(JSON.stringify({
        workspace: { projects: [], openTabs: [], activeTabId: null }
      }))
      vi.mocked(fs.writeFileSync).mockImplementationOnce(() => {
        throw new Error('ENOSPC: no space left on device')
      })

      const consoleSpy = vi.spyOn(console, 'error').mockImplementation(() => {})

      const store = new SessionStore()

      // Should not throw
      expect(() => store.saveWorkspace({
        projects: [],
        openTabs: [],
        activeTabId: null
      })).not.toThrow()

      expect(consoleSpy).toHaveBeenCalled()
      consoleSpy.mockRestore()
    })
  })

  describe('getWindowBounds() / saveWindowBounds()', () => {
    it('should return undefined when no bounds are saved', () => {
      vi.mocked(fs.existsSync).mockReturnValue(true)
      vi.mocked(fs.readFileSync).mockReturnValueOnce(JSON.stringify({
        workspace: { projects: [], openTabs: [], activeTabId: null }
      }))

      const store = new SessionStore()

      expect(store.getWindowBounds()).toBeUndefined()
    })

    it('should save and retrieve window bounds', () => {
      vi.mocked(fs.existsSync).mockReturnValue(true)
      vi.mocked(fs.readFileSync).mockReturnValueOnce(JSON.stringify({
        workspace: { projects: [], openTabs: [], activeTabId: null }
      }))

      const store = new SessionStore()
      const bounds: WindowBounds = { x: 100, y: 200, width: 800, height: 600 }

      store.saveWindowBounds(bounds)

      expect(fs.writeFileSync).toHaveBeenCalled()
      expect(store.getWindowBounds()).toEqual(bounds)
    })
  })

  describe('getSettings() / saveSettings()', () => {
    it('should return default settings when none are saved', () => {
      vi.mocked(fs.existsSync).mockReturnValue(true)
      vi.mocked(fs.readFileSync).mockReturnValueOnce(JSON.stringify({
        workspace: { projects: [], openTabs: [], activeTabId: null }
      }))

      const store = new SessionStore()
      const settings = store.getSettings()

      expect(settings).toEqual({
        defaultProjectDir: '',
        theme: 'default'
      })
    })

    it('should save and retrieve settings', () => {
      vi.mocked(fs.existsSync).mockReturnValue(true)
      vi.mocked(fs.readFileSync).mockReturnValueOnce(JSON.stringify({
        workspace: { projects: [], openTabs: [], activeTabId: null }
      }))

      const store = new SessionStore()
      const settings: Settings = {
        defaultProjectDir: '/home/user/projects',
        theme: 'dark',
        backend: 'claude',
        voiceOutputEnabled: true
      }

      store.saveSettings(settings)

      expect(fs.writeFileSync).toHaveBeenCalled()
      expect(store.getSettings()).toEqual(settings)
    })
  })

  describe('edge cases', () => {
    it('should handle workspace with all optional fields', () => {
      const fullWorkspace: Workspace = {
        projects: [{
          path: '/test',
          name: 'Test',
          executable: '/bin/test',
          apiPort: 3000,
          apiAutoStart: true,
          apiSessionMode: 'existing',
          apiModel: 'opus',
          autoAcceptTools: ['Read', 'Write'],
          permissionMode: 'dontAsk',
          color: '#ff0000',
          ttsVoice: 'test-voice',
          ttsEngine: 'piper',
          backend: 'claude',
          categoryId: 'cat1',
          order: 1
        }],
        openTabs: [{
          id: 'tab1',
          projectPath: '/test',
          sessionId: 'session1',
          title: 'Test Tab',
          backend: 'claude'
        }],
        activeTabId: 'tab1',
        viewMode: 'tiled',
        tileLayout: [{ id: 'tile1', tabIds: ['tile1'], activeTabId: 'tile1', x: 0, y: 0, width: 100, height: 100 }],
        categories: [{ id: 'cat1', name: 'Category 1', collapsed: false, order: 0 }]
      }

      vi.mocked(fs.existsSync).mockReturnValue(true)
      vi.mocked(fs.readFileSync).mockReturnValueOnce(JSON.stringify({
        workspace: fullWorkspace
      }))

      const store = new SessionStore()
      const workspace = store.getWorkspace()

      expect(workspace).toEqual(fullWorkspace)
    })

    it('should handle partial data in workspace.json', () => {
      // workspace.json might exist but have incomplete data
      vi.mocked(fs.existsSync).mockReturnValue(true)
