      break
    }
  }
  if (!shouldKeep) {
    removeSymlink(join(categoryDir, name))
  }
}

// Refresh current symlinks after removals
const remainingSymlinks = getCurrentSymlinks(categoryDir)
const existingTargets = new Set(remainingSymlinks.values())

// Create new symlinks that don't exist yet
for (const [projectPath, symlinkName] of desiredSymlinks) {
  if (!existingTargets.has(projectPath)) {
    createSymlink(projectPath, join(categoryDir, symlinkName))
  }
}
```

**Issues:**
1. **Broken symlink targets not detected**: If a symlink points to a project path that no longer exists on disk, it's kept as-is (line 104-105 in `getCurrentSymlinks` just records what's there).
2. **Rename collision not prevented**: If a project is renamed to a name that, after sanitization, collides with another project in the same category, the unique counter might not prevent the collision.
3. **No deduplication of sanitized names**: `getUniqueSymlinkName()` only checks the `existingNames` Set passed in, which is built from just the current iteration's projects. If two projects sanitize to the same name, the second gets `-2` appended, but this is lost when the function returns.
4. **Symlink integrity not validated**: No check that the symlink actually points to a valid directory. A stale symlink could persist indefinitely.

---

### **Summary Table**

| Bug # | File | Lines | Issue | Severity |
|-------|------|-------|-------|----------|
| 1 | session-store.ts | 189-197 | Temp file cleanup missing on verification failure | HIGH |
| 2 | session-store.ts | 140-151 | Backup restoration not atomic, no staleness check | HIGH |
| 3 | session-store.ts | 118-131 | Partial corruption not recoverable | MEDIUM |
| 4 | session-store.ts | 174-187 | Backup creation not atomic | HIGH |
| 5 | session-store.ts + mobile-server | 214-225, 43-89 | Empty workspace rejection silent + inconsistent | MEDIUM |
| 6 | workspace.ts + meta-project-sync.ts | 18, 80, 149 | Category sanitization has collisions | MEDIUM |
| 7 | meta-project-sync.ts | 215-252 | Stale/broken symlinks not detected | MEDIUM |

All bugs are confirmed through code inspection with exact line numbers and code snippets provided above.

